output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?opponent ?opponentLabel WHERE {
  wd:Q511040 wdt:P399 ?season .
  {
    ?season wdt:P1346 wd:Q264129 .
    ?season wdt:P1354 ?opponent .
  } UNION {
    ?season wdt:P1354 wd:Q264129 .
    ?season wdt:P1346 ?opponent .
  } MINUS {
    ?opponent wdt:P31 wd:Q15290698
  }
  FILTER(?opponent != wd:Q264129)
  OPTIONAL {
    ?opponent rdfs:label ?opponentLabel .
    FILTER(LANG(?opponentLabel) = 'en')
  }
}
ORDER BY DESC(?season)
LIMIT 1

