  wd:Q511040 wdt:P399 ?season .  # Welsh Cup's editions
  ?season wdt:P1346|wdt:P2088 wd:Q264129 ;  # Bangor City FC as winner/runner-up
        (wdt:P1346|wdt:P2088) ?opponent .
  MINUS { ?opponent wdt:P31 wd:Q15290698 }  # Exclude if opponent is a season
  OPTIONAL { ?opponent rdfs:label ?opponentLabel FILTER(LANG(?opponentLabel) = "en") }
}
LIMIT 1

SELECT ?opponent ?opponentLabel WHERE {
