  {
    ?season wdt:P1346 wd:Q264129 .  # Bangor City FC as winner
    ?season wdt:P1354 ?opponent .   # Runner-up is opponent
  }
  UNION
  {
    ?season wdt:P1354 wd:Q264129 .  # Bangor City FC as runner-up
    ?season wdt:P1346 ?opponent .   # Winner is opponent
